def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 2, -2):
                for b in range(1, a + 5):
                    inner = (ratio - a/2) ** 4 / (a * b * 0.7 + 0.5)
                    priority += inner * np.sin(ratio * b / (a - 1)) * np.exp(-ratio / a)
            priority += (np.cosh(ratio - 7) * np.tan(ratio * 1.3)) ** 1.2
            if i % 2 == 0:
                priority += np.log(ratio + 1) * 3 * np.sin(i)
        elif 5 < ratio <= 8:
            temp_sum = 0
            for p in range(1, int(np.floor(ratio)) + 4):
                for q in range(1, p + 4):
                    term = ((ratio - p) ** 2.5) * np.cos(ratio * q) / (q + p * 0.3)
                    temp_sum += np.tanh(term) * 1.5
            priority = temp_sum + np.sqrt(ratio) * 8 - np.tanh(ratio - 5) * 3
            if bin_cap < item * 1.3:
                priority += np.exp(-bin_cap / (item + 0.1)) * 4
        elif 2 <= ratio <= 5:
            s1 = 0
            for r in range(1, 15):
                s1 += ((ratio - 2) ** r) / (r ** 1.5) * np.sin(r * ratio * 1.2)
            s2 = 0
            for r2 in range(1, 8):
                s2 += np.cos(r2 * ratio) / (r2 + 0.5)
            priority = (s1 * s2) - np.log(ratio + 1) * 7 + np.tanh(5 - ratio) * 2.5
            if (i + int(item)) % 5 == 0:
                priority *= 1.3
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 20):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * np.cos(n * i * 0.7)
            penalty = np.sqrt(item / (bin_cap + 0.1)) * 3 if bin_cap < item * 1.2 else np.sin(15 * ratio) * 2
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * (i + 1)) * ((ratio - 1) ** m) / (m + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 3) + np.cos(n * item * 0.9) / (n + 1)
            priority = s
            mod_val = (i + int(item * 2)) % 6
            if mod_val == 1 or mod_val == 4:
                priority *= np.log1p(bin_cap + 4) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1.8)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.1) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 15):
                s += ((0.5 - ratio) ** k) / (k * 2.5) * np.cos(k * ratio * 3)
            priority = s + 1 / (bin_cap + 2)
            mod_item = int(item * 1.7) % 5
            if mod_item < 3:
                priority *= 2
            else:
                priority /= 2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 3.5
            else:
                priority -= np.exp(-ratio * 1.5) * 2.5
            for m in range(1, 10):
                priority += ((0.5 - ratio) ** m) / (m * 4) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.0)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.18:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 12):
                priority += ((0.2 - ratio) ** u) / (u * 9) * np.cos(item * u * 0.85)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 5 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.1) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.65
        priorities[i] = priority
    return priorities
